function solve(s) {
    // 1. Calculate frequency of each character
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    const getMirrorChar = (char) => {
        if (char >= 'a' && char <= 'z') {
            // Lowercase letters: 'a' <-> 'z', 'b' <-> 'y', etc.
            const charCode = char.charCodeAt(0);
            const zCode = 'z'.charCodeAt(0);
            // Position from 'a' is charCode - 'a'.
            // Corresponding position from 'z' (end) is zCode - charCode.
            // The mirror character code is zCode - (charCode - 'a'.charCodeAt(0)).
            const mirrorCharCode = zCode - (charCode - 'a'.charCodeAt(0));
            return String.fromCharCode(mirrorCharCode);
        } else if (char >= '0' && char <= '9') {
            // Digits: '0' <-> '9', '1' <-> '8', etc.
            const digit = parseInt(char);
            // Mirror digit is 9 - digit
            const mirrorDigit = 9 - digit;
            return String(mirrorDigit);
        }
        return null; // Should not happen based on problem constraints
    };

    let totalDifference = 0;
    const processedPairs = new Set();

    // Get all unique characters present in the string
    const uniqueChars = Array.from(freqMap.keys());

    for (const charC of uniqueChars) {
        if (processedPairs.has(charC)) {
            continue;
        }

        const charM = getMirrorChar(charC);

        if (charM === null) continue;

        // Check if the mirror character exists in the string to determine if we need to process the pair (M, C) later.
        const freqC = freqMap.get(charC);
        const freqM = freqMap.get(charM) || 0;

        if (charC === charM) {
            // Case 1: Palindromic/Self-mirroring character (e.g., 'm' and 'n' if m=n, or 4 and 5 if 4=5, which is impossible here)
            // This happens when a character is its own mirror.
            totalDifference += Math.abs(freqC - freqM); // freqM will be freqC
            processedPairs.add(charC);
            continue;
        }

        // To handle the rule: "Mirror pairs (c, m) and (m, c) are considered the same, only calculated once."
        // We enforce an order for processing: only process if charC comes lexicographically before charM.
        // This prevents double counting when we later iterate to charM.
        if (charC < charM) {
            // Calculate difference for the pair (charC, charM)
            totalDifference += Math.abs(freqC - freqM);

            // Mark both as processed to skip when we encounter charM later
            processedPairs.add(charC);
            processedPairs.add(charM);
        } else if (charC > charM) {
            // If charC > charM, it means this pair (charM, charC) would have already been processed when the loop reached charM,
            // or it will be processed when the loop reaches charM. We skip to avoid double counting.
            // We don't need to explicitly add anything to processedPairs here because we rely on the 'charC < charM' check above
            // to determine when to add to totalDifference. If we are here, charM must be in uniqueChars, and it will handle the calculation.
        }
        // If charC == charM, it was handled in the block above.
    }

    return totalDifference;
}

