use std::collections::HashMap;

fn solve(s: String) -> i64 {
    // 1. Calculate frequency of each character
    let mut freq_map: HashMap<char, i64> = HashMap::new();
    for c in s.chars() {
        *freq_map.entry(c).or_insert(0) += 1;
    }

    // Helper function to get the mirror character
    let get_mirror_char = |char_c: char| -> Option<char> {
        if char_c.is_ascii_lowercase() {
            // Lowercase letters: 'a' <-> 'z', 'b' <-> 'y', etc.
            let char_code = char_c as u8;
            let a_code = 'a' as u8;
            let z_code = 'z' as u8;
            // Mirror char code = z_code - (char_code - a_code)
            let mirror_code = z_code - (char_code - a_code);
            Some(mirror_code as char)
        } else if char_c.is_ascii_digit() {
            // Digits: '0' <-> '9', '1' <-> '8', etc.
            let digit = char_c.to_digit(10).unwrap();
            // Mirror digit is 9 - digit
            let mirror_digit = 9 - digit;
            Some(char::from_digit(mirror_digit, 10).unwrap())
        } else {
            None // Should not happen based on problem constraints
        }
    };

    let mut total_difference: i64 = 0;
    // Keep track of characters whose pairs have already been counted to avoid double counting.
    let mut processed_chars: HashMap<char, bool> = HashMap::new();

    // Get all unique characters present in the string
    let unique_chars: Vec<char> = freq_map.keys().cloned().collect();

    for char_c in unique_chars {
        if *processed_chars.get(&char_c).unwrap_or(&false) {
            continue;
        }

        let char_m = match get_mirror_char(char_c) {
            Some(m) => m,
            None => continue, // Should not happen
        };

        let freq_c = *freq_map.get(&char_c).unwrap_or(&0);
        let freq_m = *freq_map.get(&char_m).unwrap_or(&0);

        if char_c == char_m {
            // Case 1: Self-mirroring character (e.g., if 'm' mirrored to 'm')
            let diff = (freq_c - freq_m).abs();
            total_difference += diff;
            processed_chars.insert(char_c, true);
        } else {
            // Case 2: Distinct pair (c, m)
            // To ensure we count the pair only once, we only process it if char_c is lexicographically smaller than char_m.
            if char_c < char_m {
                let diff = (freq_c - freq_m).abs();
                total_difference += diff;

                // Mark both as processed
                processed_chars.insert(char_c, true);
                processed_chars.insert(char_m, true);
            }
            // If char_c > char_m, we skip because the pair (char_m, char_c) will be counted when the loop reaches char_m.
        }
    }

    total_difference
}
